class ReservationService {
    boolean isAvailable(String startDate, String endDate, int roomNumber, String guestType) {
        return checkRoomAvailability(roomNumber, startDate, endDate)
            && verifyGuestEligibility(guestType, startDate, endDate);
    }

    void makeReservation(String startDate, String endDate, int roomNumber, String guestType, String guestId) {
        if (!isAvailable(startDate, endDate, roomNumber, guestType)) {
            throw new RoomNotAvailableException();
        }
        reservationStore.save(roomNumber, guestId, startDate, endDate);
    }
}
